import{_ as a,o as e,c as n,a2 as o}from"./chunks/framework.CQMe4Urg.js";const c=JSON.parse('{"title":"第 1 章 · Python 基础","description":"","frontmatter":{},"headers":[],"relativePath":"01-python/index.md","filePath":"01-python/index.md","lastUpdated":1776333512000}'),r={name:"01-python/index.md"};function h(i,t,d,l,p,s){return e(),n("div",null,[...t[0]||(t[0]=[o('<h1 id="第-1-章-·-python-基础" tabindex="-1">第 1 章 · Python 基础 <a class="header-anchor" href="#第-1-章-·-python-基础" aria-label="Permalink to &quot;第 1 章 · Python 基础&quot;">​</a></h1><p>本书第 2-6 章和第 12 章使用 TypeScript，你可以直接从第 2 章开始学习 Agent 核心概念。但第 7-11 章（RAG、记忆、框架、Multi-Agent、评估）和第 13-16 章（安全、生产化、性能、前沿）使用 Python——因为 LangChain、LangGraph、CrewAI 等主流框架只有 Python SDK。</p><p>本章帮助有 JavaScript/TypeScript 基础的开发者快速上手 Python，为后续框架章节做准备。<strong>如果你已经熟悉 Python，可以跳过本章。</strong></p><h2 id="本章三层结构" tabindex="-1">本章三层结构 <a class="header-anchor" href="#本章三层结构" aria-label="Permalink to &quot;本章三层结构&quot;">​</a></h2><h3 id="初级-从-js-到-python" tabindex="-1">初级：从 JS 到 Python <a class="header-anchor" href="#初级-从-js-到-python" aria-label="Permalink to &quot;初级：从 JS 到 Python&quot;">​</a></h3><p>面向有 JavaScript 经验但零 Python 基础的开发者。通过 JS vs Python 对比的方式，快速建立语法映射，完成环境搭建，能写出基本的 Python 脚本。</p><p>覆盖：为什么选 Python、环境搭建（uv）、变量/函数/数据结构对比、类与异常处理。</p><h3 id="中级-异步与工程化" tabindex="-1">中级：异步与工程化 <a class="header-anchor" href="#中级-异步与工程化" aria-label="Permalink to &quot;中级：异步与工程化&quot;">​</a></h3><p>在基础语法之上，掌握 Agent 开发中高频使用的进阶特性。重点是异步编程（和 JS 的 Event Loop 对比）、装饰器、上下文管理器、包管理，以及 Pydantic 数据模型。</p><p>覆盖：async/await、装饰器、with 语句、虚拟环境、Pydantic 模型定义。</p><h3 id="高级-fastapi-与类型系统" tabindex="-1">高级：FastAPI 与类型系统 <a class="header-anchor" href="#高级-fastapi-与类型系统" aria-label="Permalink to &quot;高级：FastAPI 与类型系统&quot;">​</a></h3><p>具备独立开发生产级 Python 服务的能力。掌握 FastAPI 框架实战、Python 高级类型系统（Protocol、Generic），以及性能分析与优化技巧。</p><p>覆盖：FastAPI 完整项目、类型系统进阶、性能分析、生产最佳实践。</p><h2 id="学完能做到" tabindex="-1">学完能做到 <a class="header-anchor" href="#学完能做到" aria-label="Permalink to &quot;学完能做到&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>学完你能</th></tr></thead><tbody><tr><td>初级</td><td>读懂 Python 代码，写简单脚本，调用 LLM API</td></tr><tr><td>中级</td><td>写异步服务，用 Pydantic 定义数据模型，管理项目依赖</td></tr><tr><td>高级</td><td>用 FastAPI 构建生产级 API 服务，理解类型系统设计</td></tr></tbody></table><h2 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h2><ul><li>熟悉 JavaScript ES6+ 语法</li><li>有 Node.js 开发经验（对比学习效果更好）</li><li>不需要任何 Python 基础</li></ul>',17)])])}const y=a(r,[["render",h]]);export{c as __pageData,y as default};
